class Solution:
    def constrainedSubsetSum(self, nums, k):
        n = len(nums)
        dp = [0] * n
        for i in range(n):
            dp[i] = nums[i]
            best_prev = 0
            for j in range(max(0, i - k), i):
                best_prev = max(best_prev, dp[j])
            dp[i] += best_prev
        return max(dp)

