from collections import deque
class Solution:
    def constrainedSubsetSum(self, nums, k):
        n = len(nums)
        dp = [0] * n
        dq = deque()  # stores indices, dp values descending
        for i in range(n):
            # best previous dp in window
            best = dq[0][1] if dq and dq[0][1] > 0 else 0
            dp[i] = nums[i] + best
            # maintain deque
            while dq and dq[-1][1] <= dp[i]:
                dq.pop()
            dq.append((i, dp[i]))
            if dq[0][0] <= i - k:
                dq.popleft()
        return max(dp)

