var constrainedSubsetSum = function(nums, k) {
    const n = nums.length;
    const dp = new Array(n).fill(0);
    const dq = [];  // [index, value]
    for (let i = 0; i < n; i++) {
        const best = (dq.length > 0 && dq[0][1] > 0) ? dq[0][1] : 0;
        dp[i] = nums[i] + best;
        while (dq.length > 0 && dq[dq.length - 1][1] <= dp[i]) dq.pop();
        dq.push([i, dp[i]]);
        if (dq[0][0] <= i - k) dq.shift();
    }
    return Math.max(...dp);
};
